55	function formatDuration(ms: number): string {
56	  if (ms < 1000) {
57	    return `${ms}ms`;
58	  }
59	  if (ms < 60_000) {
60	    return `${(ms / 1000).toFixed(1)}s`;
61	  }
62	  if (ms < 3_600_000) {
63	    return `${Math.floor(ms / 60_000)}m ${Math.floor((ms % 60_000) / 1000)}s`;
64	  }
65	  return `${Math.floor(ms / 3_600_000)}h ${Math.floor((ms % 3_600_000) / 60_000)}m`;
66	}
