298	  (typeof EMPTY_STATE_MESSAGES)[keyof typeof EMPTY_STATE_MESSAGES];
299	
300	function EmptyState({ filter }: { filter: string }) {
301	  const message: EmptyStateMessageConfig =
302	    filter in EMPTY_STATE_MESSAGES
303	      ? EMPTY_STATE_MESSAGES[filter as keyof typeof EMPTY_STATE_MESSAGES]
304	      : EMPTY_STATE_MESSAGES.all;
305	  const Icon = message.icon;
