308	    <div className="flex flex-col items-center justify-center py-16 text-center">
309	      <div className="mb-4 rounded-full bg-muted/20 p-3">
310	        <Icon className="h-8 w-8 text-muted-foreground" />
311	      </div>
312	      <h3 className="mb-1 font-semibold text-sm">{message.title}</h3>
