314	        {message.description}
315	      </p>
316	      {message.showCTA && (
317	        <div className="flex flex-col gap-3">
318	          <Button size="sm" variant="outline">
319	            <FileText className="mr-2 h-4 w-4" />
320	            View documentation
321	          </Button>
322	        </div>
323	      )}
324	    </div>
