328	function JobsTable({ initialStatus, initialSearch }: JobsTableProps) {
329	  const trpc = useTRPC();
330	  const queryClient = useQueryClient();
331	  const {
332	    status: activeTab,
333	    setStatus: setActiveTab,
334	    search: searchQuery,
335	    setSearch: setSearchQuery,
336	  } = useJobFilters(initialStatus, initialSearch);
337	
338	  // Fetch jobs list
339	  const { data: jobsData } = useSuspenseQuery({
340	    ...trpc.jobs.list.queryOptions({
341	      status: activeTab === "all" ? undefined : (activeTab as JobStatus),
342	      limit: 50,
343	    }),
344	    refetchOnMount: false,
345	    refetchOnWindowFocus: false,
346	    staleTime: 10 * 1000, // 10 seconds - jobs are real-time sensitive
347	  });
348	
349	  const jobs = jobsData.items;
350	
351	  // Poll for updates every 5 seconds if there are running jobs
352	  useEffect(() => {
353	    const hasRunningJobs = jobs.some((job) => job.status === "running");
354	    if (!hasRunningJobs) {
355	      return;
356	    }
357	
358	    const interval = setInterval(() => {
359	      // Invalidate and refetch jobs list
360	      void queryClient.invalidateQueries({
361	        queryKey: trpc.jobs.list.queryOptions({
362	          status: activeTab === "all" ? undefined : (activeTab as JobStatus),
363	          limit: 50,
364	        }).queryKey,
365	      });
366	    }, 5000);
367	
368	    return () => clearInterval(interval);
369	  }, [jobs, queryClient, trpc, activeTab]);
370	
371	  // Normalize once so the filter loop doesn't lowercase on every item
372	  const searchQueryLower = useMemo(
373	    () => searchQuery.toLowerCase(),
374	    [searchQuery]
375	  );
376	
377	  const filteredJobs = useMemo(
378	    () =>
379	      jobs.filter((job) => job.name.toLowerCase().includes(searchQueryLower)),
380	    [jobs, searchQueryLower]
381	  );
382	
383	  // Single pass over all jobs to compute tab counts
384	  const { runningCount, completedCount, failedCount } = useMemo(() => {
385	    let running = 0;
386	    let completed = 0;
387	    let failed = 0;
388	    for (const j of jobs) {
389	      if (j.status === "running") {
390	        running++;
391	      } else if (j.status === "completed") {
392	        completed++;
393	      } else if (j.status === "failed") {
394	        failed++;
395	      }
396	    }
397	    return {
398	      runningCount: running,
399	      completedCount: completed,
400	      failedCount: failed,
401	    };
402	  }, [jobs]);
403	
404	  return (
405	    <div className="space-y-4">
406	      {/* Filters bar */}
407	      <div className="flex items-center justify-between gap-4">
408	        <Tabs className="flex-1" onValueChange={setActiveTab} value={activeTab}>
409	          <TabsList>
410	            <TabsTrigger value="all">All ({jobs.length})</TabsTrigger>
411	            <TabsTrigger value="running">
412	              Running ({runningCount})
413	              {runningCount > 0 && (
414	                <span className="ml-1.5 flex h-2 w-2 animate-pulse rounded-full bg-primary" />
415	              )}
416	            </TabsTrigger>
417	            <TabsTrigger value="completed">
418	              Completed ({completedCount})
419	            </TabsTrigger>
420	            <TabsTrigger value="failed">Failed ({failedCount})</TabsTrigger>
421	          </TabsList>
422	        </Tabs>
423	        <Input
424	          className="w-64"
425	          onChange={(e) => setSearchQuery(e.target.value)}
426	          placeholder="Search jobs..."
427	          value={searchQuery}
428	        />
429	      </div>
430	
431	      {/* Jobs list */}
432	      {filteredJobs.length > 0 ? (
433	        <div className="overflow-hidden rounded-lg border border-border/60">
434	          {filteredJobs.map((job) => (
435	            <JobRow job={job} key={job.id} />
436	          ))}
437	        </div>
438	      ) : (
439	        <EmptyState filter={activeTab} />
440	      )}
441	    </div>
442	  );
443	}
