398	                            className="pointer-events-none"
399	                            tabIndex={-1}
400	                          />
401	                          {renderIcon(resource)}
402	                          <div className="min-w-0 flex-1">
403	                            <div className="flex items-center gap-2">
404	                              <span className="truncate font-medium">
405	                                {resource.name}
406	                              </span>
407	                              {resource.badge && (
408	                                <span className="shrink-0 rounded border px-2 py-0.5 text-muted-foreground text-xs">
409	                                  {resource.badge}
410	                                </span>
411	                              )}
412	                            </div>
413	                            {resource.subtitle && (
414	                              <p className="mt-0.5 truncate text-muted-foreground text-xs">
415	                                {resource.subtitle}
416	                              </p>
417	                            )}
418	                          </div>
419	                        </button>
420	                      ))}
421	                    </div>
422	                  )}
423	                </div>
424	
425	                <div className="text-center text-muted-foreground text-sm">
426	                  Missing a {resourceLabel.replace(/s$/, "")}?{" "}
427	                  <button
428	                    className="text-blue-500 underline-offset-4 transition-colors hover:text-blue-600 hover:underline"
429	                    onClick={handleAdjustPermissions ?? handleConnect}
430	                    type="button"
431	                  >
432	                    {handleAdjustPermissions
433	                      ? `Adjust ${display.displayName} permissions \u2192`
434	                      : `Reconnect ${display.displayName} \u2192`}
435	                  </button>
436	                </div>
437	              </>
438	            )}
439	          </div>
440	        ) : (
441	          <div className="flex flex-col items-center gap-4 py-6 text-center">
442	            <p className="text-muted-foreground text-sm">
443	              {display.description}
444	            </p>
445	            <Button
446	              disabled={isConnecting}
447	              onClick={handleConnect}
448	              variant="outline"
449	            >
450	              <Icon className="mr-2 h-4 w-4" />
451	              Connect {display.displayName}
452	              {isConnecting && (
453	                <Loader2 className="ml-2 h-4 w-4 animate-spin" />
454	              )}
455	            </Button>
456	          </div>
457	        )}
458	      </AccordionContent>
459	    </AccordionItem>
460	  );
461	}
